 * @param {number} [options.maxRequests=100]  Max requests allowed per window.
 * @returns {Function} Express middleware with an attached `close()` method.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> — sorted-ascending arrays of request timestamps.
  const store = new Map();

  /**
   * Remove all timestamps <= cutoff. Timestamps are appended chronologically,
   * so live entries are always a contiguous suffix — find the first to keep.
   * @returns {number[]} New array of in-window timestamps, or the original
   *                     array if nothing expired.
   */
  function pruneOld(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    // NOTE ON req.ip BEHIND PROXIES:
    // `req.ip` reflects the socket's remote address unless Express "trust proxy"
    // is enabled. Behind a reverse proxy / load balancer (Nginx, ELB, Cloudflare)
    // the socket address is the proxy's, so every client would share one bucket.
    // Enable trust proxy so req.ip resolves from X-Forwarded-For:
    //     app.set('trust proxy', 1);   // or a specific subnet / true
    // Only trust proxy when you actually run behind one you control — otherwise
    // clients can spoof X-Forwarded-For to evade or poison the limiter.
    const key = req.ip || req.socket?.remoteAddress || 'unknown';

    const now = Date.now();
    const cutoff = now - windowMs; // timestamps <= cutoff are expired

    const existing = store.get(key) || [];
    const active = pruneOld(existing, cutoff);

    if (active.length >= maxRequests) {
      // ---- REJECT ----
      // A slot frees up when the OLDEST in-window request expires.
      const oldest = active[0];
      const resetMs = oldest + windowMs;
      const retryAfter = Math.max(1, Math.ceil((resetMs - now) / 1000));

      // Persist the pruned list so memory doesn't grow on rejected requests.
      store.set(key, active);

      res.setHeader('X-RateLimit-Limit', String(maxRequests));
      res.setHeader('X-RateLimit-Remaining', '0');
      res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));
      res.setHeader('Retry-After', String(retryAfter));

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter,
      });
      return; // Do NOT call next().
    }

    // ---- ALLOW ----
    active.push(now);
    store.set(key, active);

    const remaining = maxRequests - active.length;
    const resetMs = active[0] + windowMs; // when the oldest entry leaves window

    res.setHeader('X-RateLimit-Limit', String(maxRequests));
    res.setHeader('X-RateLimit-Remaining', String(remaining));
    res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));

    next();
