  // Every 60s, drop entries for IPs with no in-window activity. Without this,
  // the store retains an (empty) array for every IP ever seen.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of store) {
      const active = pruneOld(timestamps, cutoff);
      if (active.length === 0) {
        store.delete(key);
      } else if (active.length !== timestamps.length) {
