'use strict';

/**
 * sliding-window-rate-limiter.js
 *
 * True sliding-window rate limiting middleware for Express.js.
 *
 * Unlike a fixed-window counter (which resets every N seconds on a clock
 * boundary), this implementation stores the actual timestamp of every request
 * per client IP.  On each incoming request the window is recomputed from
 * "right now", so there is no burst seam at the boundary and the allowed rate
 * is enforced uniformly regardless of when within the minute the client fires.
 *
 * ─── Proxy / req.ip note ──────────────────────────────────────────────────
 * Express only reads X-Forwarded-For into req.ip when trust proxy is enabled:
 *
 *   app.set('trust proxy', 1);  // trust the first hop (e.g. Nginx / ALB)
 *
 * Without that setting, req.ip is the connecting socket address — the proxy's
 * address — so every client shares one bucket and throttles each other.
 * Set trust proxy to match your actual deployment topology (a numeric hop
 * count, or a specific IP/CIDR of your proxy) before applying this middleware.
 * ──────────────────────────────────────────────────────────────────────────
 */

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   Window size in milliseconds.
 * @property {number} [maxRequests=100]  Max requests allowed within the window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {import('express').RequestHandler} middleware  Express middleware.
 * @property {() => void}                        close      Clears the cleanup interval.
 */

/**
 * Creates a sliding-window rate-limiter.
 *
 * @param {RateLimiterOptions} [options={}]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const {
    windowMs    = 60_000, // 1 minute
    maxRequests = 100,
  } = options;

  if (!Number.isFinite(windowMs)    || windowMs    <= 0) throw new RangeError('windowMs must be a positive number');
  if (!Number.isFinite(maxRequests) || maxRequests <= 0) throw new RangeError('maxRequests must be a positive number');

  /**
   * Core store: ip → timestamp array (sorted ascending, ms epoch).
   * Entries are pruned lazily on every request AND proactively by the cleanup
   * interval, keeping memory bounded even with high cardinality of unique IPs.
   *
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ── Background cleanup ───────────────────────────────────────────────────
  // Fires every 60 s.  IPs that sent a burst and went quiet would otherwise
  // linger in the store until they send again.  The interval catches those.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;

    for (const [ip, timestamps] of store) {
      // Every timestamp for this IP has aged out — evict entirely.
      if (timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
        continue;
      }
      // Partial stale leading entries — trim them.
      const firstFresh = timestamps.findIndex(t => t > cutoff);
      if (firstFresh > 0) {
        store.set(ip, timestamps.slice(firstFresh));
      }
    }
  }, 60_000);

  // `.unref()` tells Node.js: "don't let this timer alone keep the event loop
  // alive."  The process can exit naturally even if close() is never called,
  // though calling close() on shutdown is still good practice.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  // ── Middleware ───────────────────────────────────────────────────────────
  /**
   * Sliding window algorithm per request:
   *   1. Compute windowStart = now − windowMs
   *   2. Load IP's timestamp log; drop all entries ≤ windowStart  (slide it)
   *   3. count ≥ maxRequests → 429 + Retry-After, do NOT call next()
   *   4. Otherwise, push now, set X-RateLimit-* headers, call next()
   *
   * @type {import('express').RequestHandler}
   */
  function middleware(req, res, next) {
    // req.ip requires `app.set('trust proxy', ...)` when behind a proxy.
    // Fall back to the raw socket address so the middleware never crashes
    // even in misconfigured environments.
    const ip  = req.ip ?? req.socket?.remoteAddress ?? 'unknown';
    const now = Date.now();
    const windowStart = now - windowMs; // exclusive lower bound

    // ── 1. Slide the window ────────────────────────────────────────────
    const existing   = store.get(ip) ?? [];
    const firstFresh = existing.findIndex(t => t > windowStart);
    const timestamps = firstFresh === -1
      ? []                          // every entry aged out
      : existing.slice(firstFresh); // trim stale leading portion

    // ── 2. Enforce the limit ───────────────────────────────────────────
    if (timestamps.length >= maxRequests) {
      // The oldest timestamp (index 0) slides out at: timestamps[0] + windowMs.
      // That's the earliest moment a new request can succeed.
      const retryAfterMs = (timestamps[0] + windowMs) - now;
      const retryAfterS  = Math.ceil(retryAfterMs / 1000);

      // Persist the pruned-but-still-full window; do NOT record this request.
      store.set(ip, timestamps);

      res.set('Retry-After', String(retryAfterS));
      return res
        .status(429)
        .json({ error: 'Rate limit exceeded', retryAfter: retryAfterS });
    }

    // ── 3. Record this request ─────────────────────────────────────────
    // `now` is always the largest value, so pushing keeps the array sorted
    // ascending without any explicit sort step.
    timestamps.push(now);
    store.set(ip, timestamps);

    // ── 4. Set informational headers ──────────────────────────────────
    //
    // X-RateLimit-Limit:     The cap configured for this limiter.
    // X-RateLimit-Remaining: Slots remaining in the current window for this IP.
    // X-RateLimit-Reset:     Unix epoch (seconds) when the oldest in-window
    //                        timestamp slides out, freeing the first slot.
    const remaining   = maxRequests - timestamps.length;
    const resetEpochS = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set('X-RateLimit-Limit',     String(maxRequests));
    res.set('X-RateLimit-Remaining', String(remaining));
    res.set('X-RateLimit-Reset',     String(resetEpochS));

    next();
  }

  // ── Lifecycle ────────────────────────────────────────────────────────────
  /**
   * Clears the background cleanup interval.
   * Call during graceful shutdown to prevent the timer holding the process open.
   */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
