// ── Graceful shutdown ──────────────────────────────────────────────────────
const server = app.listen(3000);

process.on('SIGTERM', () => {
  globalLimiter.close();   // clear cleanup intervals
  strictLimiter.close();
  server.close(() => process.exit(0));
});
