**Brief usage example:**

```js
const express = require('express');
const { createRateLimiter } = require('./rate-limiter');

const app = express();

// IMPORTANT: Set trust proxy before any IP-based middleware (see note in module)
app.set('trust proxy', 1);

const limiter = createRateLimiter({
  windowMs: 60 * 1000,  // 1 minute
  maxRequests: 100
});

app.use('/api', limiter);

app.get('/api/data', (req, res) => {
  res.json({ ok: true });
});

const server = app.listen(3000);

// On shutdown:
function shutdown() {
  limiter.close();                 // stop cleanup timer
  server.close(() => process.exit(0));
}
process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);
```

The implementation uses per-IP timestamp arrays, prunes on every request for a true sliding window, sets the required headers only on allowed requests, returns 429 + `Retry-After` on limit, runs a 60s cleanup that drops idle IPs, and exposes `.close()` to clear the interval.
